// Calculate date range: last 7 days with 2-day lag
const now = new Date();
const endDate = new Date(now.getTime() - 2 * 24 * 60 * 60 * 1000);
const startDate = new Date(endDate.getTime() - 7 * 24 * 60 * 60 * 1000);

return [{ json: {
  startDate: startDate.toISOString().split('T')[0],
  endDate: endDate.toISOString().split('T')[0],
  detectedAt: now.toISOString().split('T')[0]
}}];

// Detect content gaps: queries with impressions but no matching page or blog post
const gscRows = $('Fetch Query Data from GSC').first().json.rows || [];
const pagesBody = $('Get Existing Pages').first().json.body || [];
const blogsBody = $('Get Published Blog Posts').first().json.body || [];
const detectedAt = $('Calculate Date Range').first().json.detectedAt;

// Build set of existing page paths (lowercased)
const existingPages = new Set();
for (const p of pagesBody) {
  if (p.page) {
    // Extract path from full URL
    try {
      const url = new URL(p.page);
      existingPages.add(url.pathname.toLowerCase());
    } catch {
      existingPages.add(p.page.toLowerCase());
    }
  }
}

// Build set of blog keywords and titles (lowercased)
const blogKeywords = new Set();
for (const b of blogsBody) {
  if (b.target_keyword) blogKeywords.add(b.target_keyword.toLowerCase());
  if (b.title) blogKeywords.add(b.title.toLowerCase());
  if (b.slug) blogKeywords.add(b.slug.replace(/-/g, ' ').toLowerCase());
}

// Find gaps: queries with impressions but no dedicated page
const gaps = [];
for (const row of gscRows) {
  const query = row.keys[0].toLowerCase();
  const impressions = row.impressions || 0;
  const clicks = row.clicks || 0;
  const position = row.position || 100;

  if (impressions < 5) continue; // Filter noise

  // Check if query matches an existing page path
  const querySlug = query.replace(/\s+/g, '-');
  const hasPage = existingPages.has('/' + querySlug) ||
    existingPages.has('/blog/' + querySlug) ||
    existingPages.has('/services/' + querySlug);

  // Check if query matches a blog keyword/title
  const hasBlog = blogKeywords.has(query) ||
    [...blogKeywords].some(kw => kw.includes(query) || query.includes(kw));

  if (!hasPage && !hasBlog) {
    const priorityScore = Math.round(impressions * (1 - position / 100) * 100) / 100;
    gaps.push({
      query: row.keys[0],
      impressions,
      clicks,
      avg_position: Math.round(position * 100) / 100,
      priority_score: Math.max(priorityScore, 0),
      has_dedicated_page: false,
      status: 'new',
      detected_at: detectedAt
    });
  }
}

// Sort by priority_score descending, take top 30
gaps.sort((a, b) => b.priority_score - a.priority_score);
const top30 = gaps.slice(0, 30);

return [{ json: { gaps: top30, totalGaps: gaps.length, topGaps: top30.length } }];

// Build HTML email report of top 15 content gaps
const gaps = $('Detect Content Gaps').first().json.gaps || [];
const totalGaps = $('Detect Content Gaps').first().json.totalGaps || 0;
const top15 = gaps.slice(0, 15);
const detectedAt = $('Calculate Date Range').first().json.detectedAt;

if (top15.length === 0) {
  return [{ json: { skipEmail: true } }];
}

let tableRows = '';
for (let i = 0; i < top15.length; i++) {
  const g = top15[i];
  const bg = i % 2 === 0 ? '#f9f9f9' : '#ffffff';
  tableRows += `<tr style="background:${bg}">
    <td style="padding:8px;border:1px solid #ddd">${i + 1}</td>
    <td style="padding:8px;border:1px solid #ddd">${g.query}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${g.impressions}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${g.clicks}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center">${g.avg_position.toFixed(1)}</td>
    <td style="padding:8px;border:1px solid #ddd;text-align:center;font-weight:bold">${g.priority_score.toFixed(1)}</td>
  </tr>`;
}

const html = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto">
  <h2 style="color:#2d5016">TG-98 Content Gap Report</h2>
  <p style="color:#666">Week ending ${detectedAt} | ${totalGaps} total gaps found, top 15 shown</p>
  <p>These are search queries where people find impressions of tgyardcare.com but there is no dedicated page targeting that query.</p>
  <table style="border-collapse:collapse;width:100%;font-size:14px">
    <thead>
      <tr style="background:#2d5016;color:#fff">
        <th style="padding:8px;border:1px solid #ddd">#</th>
        <th style="padding:8px;border:1px solid #ddd">Query</th>
        <th style="padding:8px;border:1px solid #ddd">Impressions</th>
        <th style="padding:8px;border:1px solid #ddd">Clicks</th>
        <th style="padding:8px;border:1px solid #ddd">Avg Position</th>
        <th style="padding:8px;border:1px solid #ddd">Priority Score</th>
      </tr>
    </thead>
    <tbody>${tableRows}</tbody>
  </table>
  <p style="color:#888;font-size:12px;margin-top:16px">Priority Score = impressions * (1 - position/100). Higher = more opportunity.</p>
  <p style="color:#888;font-size:12px">Action: Create dedicated blog posts or location pages for high-priority queries.</p>
</div>`;

return [{ json: {
  skipEmail: false,
  to_email: 'totalguardllc@gmail.com',
  subject: `[TG-98] Content Gap Report - ${top15.length} Opportunities (${detectedAt})`,
  html_body: html,
  workflow_name: 'TG-98',
  email_type: 'report'
}}];
